class Solution {
public:
    int lengthOfLongestSubstring(string s) {
        int n = s.size();
        int ans = 0;
        unordered_map<char, int> last;
        int left = 0;
        for (int right = 0; right < n; right++) {
            if (last.find(s[right]) != last.end() && last[s[right]] >= left) {
                left = last[s[right]] + 1;
            }
            last[s[right]] = right;
            ans = max(ans, right - left + 1);
        }
        return ans;
    }
};
